//! Purpose:
//! Builds callable descriptor support reused by eval-to-native constructor and
//! method bridges.
//!
//! Called from:
//! - `crate::codegen_ir::finalize_user_asm()`.
//! - `crate::codegen_ir::eval_constructor_helpers` and
//!   `crate::codegen_ir::eval_method_helpers`.
//!
//! Key details:
//! - Eval stores PHP callbacks as boxed runtime values, while AOT callable
//!   parameters expect descriptor pointers.
//! - String callables and static callable arrays select static descriptors with
//!   uniform invokers generated by the existing callable dispatch machinery.

use crate::codegen::abi;
use crate::codegen::callable_descriptor::{
    self, CallableDescriptorInvocation, CallableDescriptorShape,
};
use crate::codegen::callable_dispatch::{
    self, RuntimeCallableCase, RuntimeCallableSelector, RuntimeStaticMethodCallableCase,
};
use crate::codegen::data_section::DataSection;
use crate::codegen::emit::Emitter;
use crate::ir::{Function, LocalKind, Module};
use crate::names::function_symbol;
use crate::parser::ast::Visibility;
use crate::types::{callable_wrapper_sig, PhpType};

const MIXED_METHOD_TAG_OFFSET: usize = 0;
const MIXED_METHOD_PAYLOAD_OFFSET: usize = 16;
const MIXED_RECEIVER_TAG_OFFSET: usize = 32;
const MIXED_RECEIVER_PAYLOAD_OFFSET: usize = 48;
const MIXED_SELECTOR_BYTES: usize = 64;
const MIXED_TAG_STRING: i64 = 1;

/// Callable descriptors available to eval constructor and method bridges.
pub(super) struct EvalCallableDescriptorSupport {
    string_cases: Vec<RuntimeCallableCase>,
    static_array_cases: Vec<RuntimeStaticMethodCallableCase>,
}

impl EvalCallableDescriptorSupport {
    /// Returns true when no callable descriptor case is available.
    pub(super) fn is_empty(&self) -> bool {
        self.string_cases.is_empty() && self.static_array_cases.is_empty()
    }

    /// Returns true when no static callable-array descriptor case is available.
    fn static_array_cases_empty(&self) -> bool {
        self.static_array_cases.is_empty()
    }
}

/// Returns true when eval bridges may need to turn PHP callbacks into descriptors.
pub(super) fn module_needs_eval_callable_descriptor_support(module: &Module) -> bool {
    module_uses_eval(module) && module_has_callable_aot_method_param(module)
}

/// Returns true when the EIR module contains a function that can call eval.
fn module_uses_eval(module: &Module) -> bool {
    all_module_functions(module).any(function_uses_eval)
}

/// Iterates every EIR function body emitted or inspected by the backend.
fn all_module_functions(module: &Module) -> impl Iterator<Item = &Function> {
    module
        .functions
        .iter()
        .chain(module.class_methods.iter())
        .chain(module.closures.iter())
        .chain(module.fiber_wrappers.iter())
        .chain(module.callback_wrappers.iter())
        .chain(module.extern_callback_trampolines.iter())
        .chain(module.runtime_callable_invokers.iter())
}

/// Returns true when a function has hidden eval state locals.
fn function_uses_eval(function: &Function) -> bool {
    function.locals.iter().any(|local| {
        matches!(
            local.kind,
            LocalKind::EvalContext | LocalKind::EvalScope | LocalKind::EvalGlobalScope
        )
    })
}

/// Returns true when any generated class callable exposed to eval accepts `callable`.
fn module_has_callable_aot_method_param(module: &Module) -> bool {
    module.class_infos.values().any(|class_info| {
        class_info.methods.values().any(signature_has_callable_param)
            || class_info
                .static_methods
                .values()
                .any(signature_has_callable_param)
    })
}

/// Returns true when one signature contains a callable ABI parameter.
fn signature_has_callable_param(signature: &crate::types::FunctionSig) -> bool {
    signature
        .params
        .iter()
        .any(|(_, ty)| ty.codegen_repr() == PhpType::Callable)
}

/// Emits shared runtime callable wrappers/invokers and returns descriptor cases.
pub(super) fn emit_eval_callable_descriptor_support(
    module: &Module,
    emitter: &mut Emitter,
    data: &mut DataSection,
    needed: bool,
) -> EvalCallableDescriptorSupport {
    if !needed {
        return EvalCallableDescriptorSupport {
            string_cases: Vec::new(),
            static_array_cases: Vec::new(),
        };
    }
    let mut legacy_ctx = super::lower_inst::legacy_context_from_eir_module(module);
    legacy_ctx.functions.retain(|name, _| {
        module
            .functions
            .iter()
            .any(|function| !function.flags.is_main && function.name == *name)
    });
    let string_cases = eval_user_function_callable_cases(&mut legacy_ctx, data);
    let static_array_cases = eval_static_method_callable_cases(module, &mut legacy_ctx, data);
    emit_deferred_callable_support(emitter, data, &mut legacy_ctx);
    EvalCallableDescriptorSupport {
        string_cases,
        static_array_cases,
    }
}

/// Builds descriptor cases for user functions visible as eval string callables.
fn eval_user_function_callable_cases(
    legacy_ctx: &mut crate::codegen::context::Context,
    data: &mut DataSection,
) -> Vec<RuntimeCallableCase> {
    let mut functions = legacy_ctx
        .functions
        .iter()
        .map(|(name, sig)| (name.clone(), sig.clone()))
        .collect::<Vec<_>>();
    functions.sort_by(|left, right| left.0.cmp(&right.0));
    let mut cases = Vec::with_capacity(functions.len());
    for (name, sig) in functions {
        let case_sig = callable_wrapper_sig(&sig);
        let invoker_label =
            callable_dispatch::ensure_runtime_descriptor_invoker(legacy_ctx, &[], &case_sig);
        let descriptor_label = callable_descriptor::static_descriptor_with_optional_invoker_meta(
            data,
            &function_symbol(&name),
            Some(&name),
            callable_descriptor::CALLABLE_DESC_KIND_FUNCTION,
            Some(&case_sig),
            &[],
            &[],
            CallableDescriptorInvocation::named(CallableDescriptorShape::Function, &name),
            invoker_label.as_deref(),
        );
        cases.push(RuntimeCallableCase {
            label: function_symbol(&name),
            descriptor_label,
            php_name: Some(name),
            sig: case_sig,
            captures: Vec::new(),
            has_invoker: invoker_label.is_some(),
            invoker_label,
        });
    }
    cases
}

/// Builds descriptor cases for emitted public static methods visible to eval.
fn eval_static_method_callable_cases(
    module: &Module,
    legacy_ctx: &mut crate::codegen::context::Context,
    data: &mut DataSection,
) -> Vec<RuntimeStaticMethodCallableCase> {
    let emitted_methods = super::eir_class_method_keys(module);
    let mut candidates = Vec::new();
    for (class_name, class_info) in &module.class_infos {
        for method_name in class_info.static_methods.keys() {
            if !class_info
                .static_method_visibilities
                .get(method_name)
                .is_some_and(|visibility| matches!(visibility, Visibility::Public))
            {
                continue;
            }
            let method_key = crate::names::php_symbol_key(method_name);
            let impl_class = class_info
                .static_method_impl_classes
                .get(&method_key)
                .map(String::as_str)
                .unwrap_or(class_name);
            if emitted_methods.contains(&(impl_class.to_string(), method_key, true)) {
                candidates.push((class_name.clone(), method_name.clone()));
            }
        }
    }
    candidates.sort_by(|left, right| (&left.0, &left.1).cmp(&(&right.0, &right.1)));
    candidates
        .into_iter()
        .filter_map(|(class_name, method_name)| {
            callable_dispatch::runtime_static_method_case(
                legacy_ctx,
                data,
                &class_name,
                &method_name,
            )
            .map(|case| RuntimeStaticMethodCallableCase {
                class_name,
                method_name,
                case,
            })
        })
        .collect()
}

/// Emits deferred callable support bodies behind one jump.
fn emit_deferred_callable_support(
    emitter: &mut Emitter,
    data: &mut DataSection,
    legacy_ctx: &mut crate::codegen::context::Context,
) {
    if legacy_ctx.deferred_closures.is_empty()
        && legacy_ctx.deferred_fiber_wrappers.is_empty()
        && legacy_ctx.deferred_callback_wrappers.is_empty()
        && legacy_ctx.deferred_extern_callback_trampolines.is_empty()
        && legacy_ctx.deferred_runtime_callable_invokers.is_empty()
    {
        return;
    }
    let done_label = legacy_ctx.next_label("eval_callable_support_done");
    abi::emit_jump(emitter, &done_label);
    crate::codegen::emit_deferred_closures(emitter, data, legacy_ctx);
    emitter.label(&done_label);
}

/// Converts the ARM64 boxed eval argument slot into a callable descriptor pointer.
pub(super) fn emit_aarch64_cast_eval_callable_arg(
    module: &Module,
    emitter: &mut Emitter,
    data: &mut DataSection,
    support: &EvalCallableDescriptorSupport,
    label_prefix: &str,
    fail_label: &str,
) {
    let string_label = format!("{}_callable_string", label_prefix);
    let array_label = format!("{}_callable_array", label_prefix);
    emitter.instruction("ldr x0, [x29, #-16]");                                 // reload the boxed eval argument for callable validation
    emitter.instruction("bl __rt_mixed_unbox");                                 // expose the eval callable tag and payload words
    emitter.instruction("cmp x0, #1");                                          // runtime tag 1 means a string callable name
    emitter.instruction(&format!("b.eq {}", string_label));                     // resolve string callables through descriptor metadata
    emitter.instruction("cmp x0, #4");                                          // runtime tag 4 means an indexed callable array
    emitter.instruction(&format!("b.eq {}", array_label));                      // resolve static callable arrays through descriptor metadata
    emitter.instruction("cmp x0, #5");                                          // runtime tag 5 means an associative callable array
    emitter.instruction(&format!("b.eq {}", array_label));                      // resolve static callable arrays with numeric keys
    abi::emit_jump(emitter, fail_label);
    emitter.label(&string_label);
    abi::emit_push_reg_pair(emitter, "x1", "x2");
    emit_eval_string_callable_descriptor_lookup(
        module,
        emitter,
        data,
        support,
        label_prefix,
        fail_label,
        "x0",
    );
    abi::emit_jump(emitter, &format!("{}_callable_cast_done", label_prefix));
    emitter.label(&array_label);
    emit_aarch64_eval_callable_array_selector_slots(module, emitter);
    emit_eval_static_callable_array_descriptor_lookup(
        emitter,
        data,
        support,
        label_prefix,
        fail_label,
        "x0",
    );
    emitter.label(&format!("{}_callable_cast_done", label_prefix));
}

/// Converts the x86_64 boxed eval argument slot into a callable descriptor pointer.
pub(super) fn emit_x86_64_cast_eval_callable_arg(
    module: &Module,
    emitter: &mut Emitter,
    data: &mut DataSection,
    support: &EvalCallableDescriptorSupport,
    label_prefix: &str,
    fail_label: &str,
) {
    let string_label = format!("{}_callable_string", label_prefix);
    let array_label = format!("{}_callable_array", label_prefix);
    emitter.instruction("mov rax, QWORD PTR [rbp - 40]");                       // reload the boxed eval argument for callable validation
    emitter.instruction("call __rt_mixed_unbox");                               // expose the eval callable tag and payload words
    emitter.instruction("cmp rax, 1");                                          // runtime tag 1 means a string callable name
    emitter.instruction(&format!("je {}", string_label));                       // resolve string callables through descriptor metadata
    emitter.instruction("cmp rax, 4");                                          // runtime tag 4 means an indexed callable array
    emitter.instruction(&format!("je {}", array_label));                        // resolve static callable arrays through descriptor metadata
    emitter.instruction("cmp rax, 5");                                          // runtime tag 5 means an associative callable array
    emitter.instruction(&format!("je {}", array_label));                        // resolve static callable arrays with numeric keys
    abi::emit_jump(emitter, fail_label);
    emitter.label(&string_label);
    abi::emit_push_reg_pair(emitter, "rdi", "rdx");
    emit_eval_string_callable_descriptor_lookup(
        module,
        emitter,
        data,
        support,
        label_prefix,
        fail_label,
        "rax",
    );
    abi::emit_jump(emitter, &format!("{}_callable_cast_done", label_prefix));
    emitter.label(&array_label);
    emit_x86_64_eval_callable_array_selector_slots(module, emitter);
    emit_eval_static_callable_array_descriptor_lookup(
        emitter,
        data,
        support,
        label_prefix,
        fail_label,
        "rax",
    );
    emitter.label(&format!("{}_callable_cast_done", label_prefix));
}

/// Looks up a descriptor by the string callable currently saved on the temp stack.
fn emit_eval_string_callable_descriptor_lookup(
    module: &Module,
    emitter: &mut Emitter,
    data: &mut DataSection,
    support: &EvalCallableDescriptorSupport,
    label_prefix: &str,
    fail_label: &str,
    result_reg: &str,
) {
    let done_label = format!("{}_callable_done", label_prefix);
    let miss_label = format!("{}_callable_missing", label_prefix);
    if support.is_empty() {
        abi::emit_release_temporary_stack(emitter, 16);
        abi::emit_jump(emitter, fail_label);
        return;
    }
    let selector = RuntimeCallableSelector::StringNameStack {
        ptr_offset: 0,
        len_offset: 8,
        call_reg: result_reg,
    };
    let mut legacy_ctx = super::lower_inst::legacy_context_from_eir_module(module);
    for case in support
        .string_cases
        .iter()
        .chain(support.static_array_cases.iter().map(|case| &case.case))
    {
        let next_case = legacy_ctx.next_label("eval_callable_next");
        callable_dispatch::emit_branch_if_callable_case_mismatch(
            &selector,
            case,
            &next_case,
            emitter,
            &mut legacy_ctx,
            data,
        );
        abi::emit_jump(emitter, &done_label);
        emitter.label(&next_case);
    }
    abi::emit_jump(emitter, &miss_label);
    emitter.label(&miss_label);
    abi::emit_release_temporary_stack(emitter, 16);
    abi::emit_jump(emitter, fail_label);
    emitter.label(&done_label);
    abi::emit_release_temporary_stack(emitter, 16);
}

/// Saves the receiver and method slots from an ARM64 boxed eval callable array.
fn emit_aarch64_eval_callable_array_selector_slots(module: &Module, emitter: &mut Emitter) {
    emit_aarch64_eval_callable_array_slot(module, emitter, 0);
    emit_aarch64_push_mixed_unbox_payload(emitter);
    emit_aarch64_eval_callable_array_slot(module, emitter, 1);
    emit_aarch64_push_mixed_unbox_payload(emitter);
}

/// Saves the receiver and method slots from an x86_64 boxed eval callable array.
fn emit_x86_64_eval_callable_array_selector_slots(module: &Module, emitter: &mut Emitter) {
    emit_x86_64_eval_callable_array_slot(module, emitter, 0);
    emit_x86_64_push_mixed_unbox_payload(emitter);
    emit_x86_64_eval_callable_array_slot(module, emitter, 1);
    emit_x86_64_push_mixed_unbox_payload(emitter);
}

/// Loads and unboxes one ARM64 callable-array slot through eval's array reader.
fn emit_aarch64_eval_callable_array_slot(module: &Module, emitter: &mut Emitter, index: usize) {
    let value_int_symbol = module.target.extern_symbol("__elephc_eval_value_int");
    let array_get_symbol = module.target.extern_symbol("__elephc_eval_value_array_get");
    abi::emit_load_int_immediate(emitter, "x0", index as i64);
    abi::emit_call_label(emitter, &value_int_symbol);
    emitter.instruction("str x0, [sp, #-16]!");                                 // preserve the boxed callable-array index
    emitter.instruction("ldr x1, [sp]");                                        // pass the boxed selector index to eval's array reader
    emitter.instruction("ldr x0, [x29, #-16]");                                 // pass the boxed callable array to eval's array reader
    abi::emit_call_label(emitter, &array_get_symbol);
    emitter.instruction("add sp, sp, #16");                                     // discard the temporary boxed selector index
    emitter.instruction("bl __rt_mixed_unbox");                                 // expose the callable-array selector slot tag and payload
}

/// Loads and unboxes one x86_64 callable-array slot through eval's array reader.
fn emit_x86_64_eval_callable_array_slot(module: &Module, emitter: &mut Emitter, index: usize) {
    let value_int_symbol = module.target.extern_symbol("__elephc_eval_value_int");
    let array_get_symbol = module.target.extern_symbol("__elephc_eval_value_array_get");
    abi::emit_load_int_immediate(emitter, "rdi", index as i64);
    abi::emit_call_label(emitter, &value_int_symbol);
    abi::emit_push_reg(emitter, "rax");
    emitter.instruction("mov rsi, QWORD PTR [rsp]");                            // pass the boxed selector index to eval's array reader
    emitter.instruction("mov rdi, QWORD PTR [rbp - 40]");                       // pass the boxed callable array to eval's array reader
    abi::emit_call_label(emitter, &array_get_symbol);
    emitter.instruction("add rsp, 16");                                         // discard the temporary boxed selector index
    emitter.instruction("call __rt_mixed_unbox");                               // expose the callable-array selector slot tag and payload
}

/// Preserves the current ARM64 mixed-unbox tag and payload on the temp stack.
fn emit_aarch64_push_mixed_unbox_payload(emitter: &mut Emitter) {
    abi::emit_push_reg_pair(emitter, "x1", "x2");
    abi::emit_push_reg(emitter, "x0");
}

/// Preserves the current x86_64 mixed-unbox tag and payload on the temp stack.
fn emit_x86_64_push_mixed_unbox_payload(emitter: &mut Emitter) {
    abi::emit_push_reg_pair(emitter, "rdi", "rdx");
    abi::emit_push_reg(emitter, "rax");
}

/// Looks up a static-method descriptor from saved callable-array selector slots.
fn emit_eval_static_callable_array_descriptor_lookup(
    emitter: &mut Emitter,
    data: &mut DataSection,
    support: &EvalCallableDescriptorSupport,
    label_prefix: &str,
    fail_label: &str,
    result_reg: &str,
) {
    let done_label = format!("{}_callable_array_done", label_prefix);
    let miss_label = format!("{}_callable_array_missing", label_prefix);
    if support.static_array_cases_empty() {
        abi::emit_release_temporary_stack(emitter, MIXED_SELECTOR_BYTES);
        abi::emit_jump(emitter, fail_label);
        return;
    }
    for (index, case) in support.static_array_cases.iter().enumerate() {
        let next_case = format!("{}_callable_array_next_{}", label_prefix, index);
        emit_branch_if_static_callable_array_case_mismatch(
            emitter,
            data,
            case,
            &next_case,
        );
        abi::emit_symbol_address(emitter, result_reg, &case.case.descriptor_label);
        abi::emit_jump(emitter, &done_label);
        emitter.label(&next_case);
    }
    abi::emit_jump(emitter, &miss_label);
    emitter.label(&miss_label);
    abi::emit_release_temporary_stack(emitter, MIXED_SELECTOR_BYTES);
    abi::emit_jump(emitter, fail_label);
    emitter.label(&done_label);
    abi::emit_release_temporary_stack(emitter, MIXED_SELECTOR_BYTES);
}

/// Branches unless saved selector slots match one static callable-array case.
fn emit_branch_if_static_callable_array_case_mismatch(
    emitter: &mut Emitter,
    data: &mut DataSection,
    case: &RuntimeStaticMethodCallableCase,
    next_label: &str,
) {
    emit_branch_if_stack_tag_mismatch(emitter, MIXED_RECEIVER_TAG_OFFSET, MIXED_TAG_STRING, next_label);
    emit_branch_if_stack_tag_mismatch(emitter, MIXED_METHOD_TAG_OFFSET, MIXED_TAG_STRING, next_label);
    emit_branch_if_static_class_string_mismatch(
        emitter,
        data,
        MIXED_RECEIVER_PAYLOAD_OFFSET,
        MIXED_RECEIVER_PAYLOAD_OFFSET + 8,
        &case.class_name,
        next_label,
    );
    emit_branch_if_stack_string_mismatch(
        emitter,
        data,
        MIXED_METHOD_PAYLOAD_OFFSET,
        MIXED_METHOD_PAYLOAD_OFFSET + 8,
        case.method_name.as_bytes(),
        next_label,
    );
}

/// Branches when a saved Mixed tag stack slot does not equal `expected_tag`.
fn emit_branch_if_stack_tag_mismatch(
    emitter: &mut Emitter,
    tag_offset: usize,
    expected_tag: i64,
    next_label: &str,
) {
    match emitter.target.arch {
        crate::codegen::platform::Arch::AArch64 => {
            abi::emit_load_temporary_stack_slot(emitter, "x9", tag_offset);
            emitter.instruction(&format!("cmp x9, #{}", expected_tag));         // compare the callable-array selector runtime tag
            emitter.instruction(&format!("b.ne {}", next_label));               // try the next callable-array target when the tag differs
        }
        crate::codegen::platform::Arch::X86_64 => {
            abi::emit_load_temporary_stack_slot(emitter, "r10", tag_offset);
            emitter.instruction(&format!("cmp r10, {}", expected_tag));         // compare the callable-array selector runtime tag
            emitter.instruction(&format!("jne {}", next_label));                // try the next callable-array target when the tag differs
        }
    }
}

/// Branches when a saved stack string does not match the expected PHP name.
fn emit_branch_if_stack_string_mismatch(
    emitter: &mut Emitter,
    data: &mut DataSection,
    ptr_offset: usize,
    len_offset: usize,
    expected: &[u8],
    next_label: &str,
) {
    let matched_label = format!("{}_matched", next_label);
    emit_stack_string_compare_branch(emitter, data, ptr_offset, len_offset, expected, &matched_label);
    abi::emit_jump(emitter, next_label);
    emitter.label(&matched_label);
}

/// Branches when a saved class string does not match bare or leading-slash forms.
fn emit_branch_if_static_class_string_mismatch(
    emitter: &mut Emitter,
    data: &mut DataSection,
    ptr_offset: usize,
    len_offset: usize,
    class_name: &str,
    next_label: &str,
) {
    let matched_label = format!("{}_class_matched", next_label);
    emit_stack_string_compare_branch(
        emitter,
        data,
        ptr_offset,
        len_offset,
        class_name.as_bytes(),
        &matched_label,
    );
    let leading_slash = format!("\\{}", class_name);
    emit_stack_string_compare_branch(
        emitter,
        data,
        ptr_offset,
        len_offset,
        leading_slash.as_bytes(),
        &matched_label,
    );
    abi::emit_jump(emitter, next_label);
    emitter.label(&matched_label);
}

/// Compares a saved stack string with `expected` and branches on equality.
fn emit_stack_string_compare_branch(
    emitter: &mut Emitter,
    data: &mut DataSection,
    ptr_offset: usize,
    len_offset: usize,
    expected: &[u8],
    matched_label: &str,
) {
    let (expected_label, expected_len) = data.add_string(expected);
    match emitter.target.arch {
        crate::codegen::platform::Arch::AArch64 => {
            abi::emit_load_temporary_stack_slot(emitter, "x1", ptr_offset);
            abi::emit_load_temporary_stack_slot(emitter, "x2", len_offset);
            abi::emit_symbol_address(emitter, "x3", &expected_label);
            abi::emit_load_int_immediate(emitter, "x4", expected_len as i64);
            abi::emit_call_label(emitter, "__rt_strcasecmp");
            emitter.instruction("cmp x0, #0");                                  // check whether the runtime method string matched
            emitter.instruction(&format!("b.eq {}", matched_label));            // select this callable-array target when names match
        }
        crate::codegen::platform::Arch::X86_64 => {
            abi::emit_load_temporary_stack_slot(emitter, "rdi", ptr_offset);
            abi::emit_load_temporary_stack_slot(emitter, "rsi", len_offset);
            abi::emit_symbol_address(emitter, "rdx", &expected_label);
            abi::emit_load_int_immediate(emitter, "rcx", expected_len as i64);
            abi::emit_call_label(emitter, "__rt_strcasecmp");
            emitter.instruction("test rax, rax");                               // check whether the runtime method string matched
            emitter.instruction(&format!("je {}", matched_label));              // select this callable-array target when names match
        }
    }
}
